sp_widget.client_script:
api.controller=function($scope, $filter, spUtil,spModal) {
  /* widget controller */
  var c = this;
	$scope.showingHistory=false;

	// catch view history click from Scheduled OoO widget
	$scope.$on('$oooViewHistory', function () {
		$scope.showingHistory=true;	
	});	

	$scope.showSchedule = function(){
		$scope.showingHistory=false;		
	};

	$scope.showHistory = function(){
		$scope.showingHistory=true;		
	};

	// *******************************************
	// START NEW OOO MENU OPTION
	// *******************************************
	$scope.newOOO = function(){
		spModal.open({
			message: '',
			backdrop: 'static',
			widget: 'discovertasker-formtab',
			widgetInput: {
				table: c.data.table,
				sys_id: -1,
				query: c.data.newFilter,
				hideRelatedLists: false,
				omitHeader: true,
				bifold: false,
				hideAttachmentBtn: true,
				isModal: true
			},
			shared: {},
			//size: 'lg',
			buttons: [''],
			footerStyle: {
				'display': 'none'
			}
		}).then(function(){
			spUtil.update($scope);
		}, function() {
				spUtil.update($scope);
		});
	};
	// *******************************************
	// END NEW OOO MENU OPTION
	// *******************************************

	// *******************************************
	// START OF FLEX STYLING
	// *******************************************
	$scope.getPanelPanelCssByPageId = function() {
		var panelClassNames = '';
		if (c.data.page_id == undefined && c.data.isModal == true || c.data.bifold) {
			panelClassNames = 'flex-column flex-grow';
		} else if (c.data.omitHeader == true && c.data.bifold == false && c.data.isModal == false) {
			panelClassNames = 'flex-column flex-grow';
		} else {
			panelClassNames = '';
		}

		return panelClassNames;
	};

	$scope.getPanelBodyCss = function() {
		var panelBodyClassNames = '';
		if (c.data.page_id == undefined && c.data.isModal == true || c.data.bifold) {
			panelBodyClassNames = 'flex-column flex-grow dtech-overflow-hidden dtech-pad-all-0 dtech-pad-bottom-5';
		}
		return panelBodyClassNames;
	};

	// *******************************************
	// START OF FLEX STYLING
	// *******************************************

};

sp_widget.css:
.ooo-flex-container {
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}
.ooo-back-div-height {
  height:40px;
}
.ooo-dnd-width {
  width:166px;
  height:166px;
  margin-left:30px;
}

.ooo-profile-card {
  padding-left:20px;
  display: flex;
  flex-direction: row;
  align-items: start;
  justify-content: start;
}
.ooo-header-padding {
  padding-top: 50px;
  padding-bottom: 40px;
}
.ooo-panel-padding {
  padding-left: 20px;
  padding-right: 20px;
}

.ooo-bottom-padding {
  padding-bottom: 20px;
}

.ooo-24-light {
  font-family:SourceSansPro;
  font-size:24px;
  font-weight:100;
  color:#000000;
}
.ooo-no-active-schedules {
  font-family: SourceSansPro;
  font-size: 16px;
  font-weight: 600;
  color: #000000;
}
.ooo-btn{
  margin-top: 20px;
  color: #FFFFFF;
  font-size: 14px;
  font-weight: 400;
  border-radius: 5px;
  background-color: #00A4FF;
  border-color: #00A4FF;  
  border-style: solid;
  box-shadow: 0px 3px 6px 0px rgba(0,0,0,0.25);
}

.ooo-btn:hover{
  color: #FFFFFF;
  background-color: #0087D2;
  border-color: #0087D2;
}

.ooo-btn:focus{
  color: #FFFFFF;
  background-color: #00A4FF;
  border-color: #0087D2;
}

.ooo-btn:disabled {
  color: #FFFFFF;
  background-color: #757575;
  border-color: #757575;
  cursor: none;
}

.ooo-text{
  font-family: SourceSansPro, Helvetica, Arial, sans-serif;
  font-size: 14px;
  color: #757575;
}

.ooo-backbtn{
  width: 100%;
  height: 30px;
  background-color: none;
  color: black;
  border-radius: 5px;
  box-shadow: none;
}
.ooo-backbtn:hover{
  background-color: #d9edf7;
  box-shadow:0px 0px 0px 2px #d9edf7 inset;
  cursor: pointer;
}
.ooo-backbtn:focus{
  box-shadow:0px 0px 0px 2px #00A4FF inset;
}

.ooo-hyperlink{
  width: 100%;
  height: 32px;
  background-color: none;
  border-radius: 5px;
  text-decoration: underline;
  font-family: SourceSansPro, Helvetica, Arial, sans-serif;
  font-size: 14px;
  color: #000000;
  font-weight: 400;
  line-height: 28px;
  box-shadow: none;
}

.ooo-hyperlink:hover{
  color: #0087D2;
  cursor: pointer;
}

.ooo-hyperlink:focus{
  box-shadow:0px 0px 0px 2px #00A4FF inset;
}

.ooo-hyperlink:disabled {
  color: #757575;
  cursor: none;
}

